func providerAPIMailTransportLabel(provider string) string {
	if strings.EqualFold(strings.TrimSpace(provider), "outlook") {
		return "Microsoft Graph"
	}
	return "Gmail API"
}

func providerAPIMailPanelTitle(provider string, mode string) string {
	if mode == "send" {
		if strings.EqualFold(strings.TrimSpace(provider), "outlook") {
			return "Outlook Sending"
		}
		return "Gmail Sending"
	}
	if strings.EqualFold(strings.TrimSpace(provider), "outlook") {
		return "Outlook Mail"
	}
	return "Gmail Mail"
}

func providerAPIMailPanelDescription(provider string, mode string) string {
	if strings.EqualFold(strings.TrimSpace(provider), "outlook") {
		if mode == "send" {
			return "Outlook messages and drafts are sent through Microsoft Graph. SMTP server settings are not used for this account."
		}
		return "Outlook mail is read through Microsoft Graph delta sync. IMAP server settings are not used for this account."
	}
	if mode == "send" {
		return "Gmail messages and drafts are sent through the Gmail API. SMTP server settings are not used for this account."
	}
	return "Gmail mail is read through Gmail API history changes. IMAP server settings are not used for this account."
}

