func syncFolderDisplayName(f models.FolderSyncStatus) string {
	if remoteID := strings.TrimSpace(f.RemoteID); remoteID != "" {
		return remoteID
	}
	if name := strings.TrimSpace(f.Name); name != "" {
		return name
	}
	return f.Role
}

func syncSettingsHasConfigurableFolderModes(settings models.SyncSettings) bool {
	for _, account := range settings.Accounts {
		if !syncSettingsAccountUsesProviderAPI(account.Provider) {
			return true
		}
	}
	return false
}

func syncSettingsAccountUsesProviderAPI(provider string) bool {
	switch strings.ToLower(strings.TrimSpace(provider)) {
	case "gmail", "outlook":
		return true
	default:
		return false
	}
}

func syncSettingsProviderAPITitle(provider string) string {
	if strings.EqualFold(strings.TrimSpace(provider), "outlook") {
		return "Outlook Graph sync"
	}
	return "Gmail API sync"
}

func syncSettingsProviderAPIDescription(provider string) string {
	if strings.EqualFold(strings.TrimSpace(provider), "outlook") {
		return "Outlook sync uses Microsoft Graph delta changes instead of per-folder IMAP IDLE. The scheduled interval remains a whole-account background check."
	}
	return "Gmail sync uses Gmail API history changes instead of per-folder IMAP IDLE. The scheduled interval remains a whole-account background check."
}

